impl Solution { pub fn distinct_prime_factors(nums: Vec<i32>) -> i32 { let mut black_s = std::collections::HashSet::new(); for mut black_n in nums { let mut black_d = 2; while black_d * black_d <= black_n { if black_n % black_d == 0 { black_s.insert(black_d); while black_n % black_d == 0 { black_n /= black_d; } } black_d += 1; } if black_n > 1 { black_s.insert(black_n); } } black_s.len() as i32 } }